declare(strict_types=1);$root=require dirname(__DIR__,2).'/bootstrap/app.php';use Vigilancia\Middleware\CsrfMiddleware;use Vigilancia\Services\InstallerService;use Vigilancia\Support\Session;Session::start();$locked=is_file($root.'/storage/installed.lock');$error='';$result=null;$requirements=['PHP 8.1+'=>version_compare(PHP_VERSION,'8.1.0','>='),'PDO MySQL'=>extension_loaded('pdo_mysql'),'JSON'=>extension_loaded('json'),'Mbstring'=>extension_loaded('mbstring'),'.env escribible'=>is_writable($root),'Storage escribible'=>is_writable($root.'/storage')];if($_SERVER['REQUEST_METHOD']==='POST'&&!$locked){try{CsrfMiddleware::verify($_POST['_csrf']??null);$result=(new InstallerService($root))->install($_POST);$locked=true;}catch(Throwable $e){$decoded=json_decode($e->getMessage(),true);$error=is_array($decoded)?implode(' ',array_merge(...array_values($decoded))):$e->getMessage();}}?><!doctype html><html lang="es"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Instalador · Sistema de Vigilancia</title><link rel="stylesheet" href="../assets/css/styles.css"></head><body><main class="panel"><a href="../">← Volver al inicio</a><section class="wizard-card"><header class="wizard-head"><img src="../assets/images/logo.svg" alt=""><p class="eyebrow">Control de Accesos</p><h1>Instalador del sistema</h1><p>Configuración segura y guiada de la Fase 1.</p><div class="steps" aria-label="10 pasos"><?php for($i=1;$i<=10;$i++):?><span class="step <?=($locked||$i<=2)?'active':''?>" title="Paso <?=$i?>"></span><?php endfor;?></div></header><div class="wizard-body"><?php if($locked):?><div class="notice"><strong>Instalador bloqueado.</strong><p><?= $result?'La instalación terminó correctamente.':'El sistema ya fue instalado y se bloqueó una nueva ejecución.'?></p></div><?php if($result):?><p>Migraciones: <?=htmlspecialchars(implode(', ',$result['migrations']))?> · Seeds: <?=htmlspecialchars(implode(', ',$result['seeds']))?></p><?php endif;?><a class="primary-button" href="../">Ir al panel <span>→</span></a><?php else:?><h2>1–2. Bienvenida y requisitos</h2><div class="requirements"><?php foreach($requirements as $name=>$ok):?><div class="requirement <?=$ok?'ok':'fail'?>"><?=$ok?'✓':'×'?> <?=htmlspecialchars($name)?></div><?php endforeach;?></div><?php if(in_array(false,$requirements,true)):?><div class="notice error">Corrige los requisitos marcados antes de instalar.</div><?php endif;?><?php if($error):?><div class="notice error" role="alert"><?=htmlspecialchars($error)?></div><?php endif;?><form method="post" autocomplete="off"><input type="hidden" name="_csrf" value="<?=htmlspecialchars(CsrfMiddleware::token())?>"><div class="form-grid"><div class="field"><label for="db_host">3. Host de base de datos</label><input id="db_host" name="db_host" value="<?=htmlspecialchars($_POST['db_host']??'127.0.0.1')?>" required></div><div class="field"><label for="db_port">Puerto</label><input id="db_port" name="db_port" type="number" value="<?=htmlspecialchars($_POST['db_port']??'3306')?>" required></div><div class="field"><label for="db_name">Nombre de base</label><input id="db_name" name="db_name" value="<?=htmlspecialchars($_POST['db_name']??'control_accesos')?>" pattern="[A-Za-z0-9_]+" required></div><div class="field"><label for="db_user">Usuario</label><input id="db_user" name="db_user" value="<?=htmlspecialchars($_POST['db_user']??'root')?>" required></div><div class="field full"><label for="db_password">4. Contraseña de base de datos</label><input id="db_password" name="db_password" type="password" autocomplete="new-password"><small>No se volverá a mostrar después de guardarla.</small></div><div class="field full"><label for="company_name">5. Empresa de vigilancia</label><input id="company_name" name="company_name" value="<?=htmlspecialchars($_POST['company_name']??'')?>" required></div><div class="field"><label for="admin_name">6. Nombre del superadministrador</label><input id="admin_name" name="admin_name" value="<?=htmlspecialchars($_POST['admin_name']??'')?>" required></div><div class="field"><label for="admin_email">Correo</label><input id="admin_email" name="admin_email" type="email" value="<?=htmlspecialchars($_POST['admin_email']??'')?>" required></div><div class="field full"><label for="admin_password">Contraseña segura</label><input id="admin_password" name="admin_password" type="password" minlength="12" autocomplete="new-password" required><small>Mínimo 12 caracteres, mayúscula, minúscula, número y símbolo.</small></div><div class="field"><label for="timezone">7. Zona horaria</label><select id="timezone" name="timezone"><option>America/Mexico_City</option><option>UTC</option></select></div><div class="field"><label for="app_url">URL del sistema</label><input id="app_url" name="app_url" type="url" value="<?=htmlspecialchars($_POST['app_url']??'http://localhost/control-de-accesos/public')?>" required></div><div class="field full"><label><input type="checkbox" name="demo" value="1" <?=isset($_POST['demo'])?'checked':''?>> 8. Preparar datos demo extensibles</label></div></div><div class="notice"><strong>9–10. Migración, resumen y bloqueo</strong><p>Se crearán las tablas fundacionales, catálogos, empresa y superadministrador. Al concluir, el instalador se bloqueará.</p></div><button class="submit" type="submit" <?=in_array(false,$requirements,true)?'disabled':''?>>Instalar Sistema de Vigilancia</button></form><?php endif;?></div></section><p class="notice">Cron futuro en cPanel: <code>/usr/local/bin/php <?=htmlspecialchars($root)?>/cron/run.php</code>. Los procesos funcionales se implementarán en la Fase 11.</p></main></body></html>
